#define LIMIT -999

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

int maximum(int a, int b, int c) {
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

__attribute__((reqd_work_group_size(BLOCK_SIZE, 1, 1)))
void nw_kernel1(__global int* referrence,
                __global int* input_itemsets,
                __global int* output_itemsets,
                __local int* input_itemsets_l,
                __local int* reference_l,
                int max_cols,
                int penalty,
                int blk,
                int block_width,
                int worksize,
                int offset_r,
                int offset_c)
{
    int local_id = get_local_id(0);
    int group_id = get_group_id(0);

    // In the OpenMP code, the loop iterates b_index_x from 0 to blk-1.
    // Each iteration is a independent block computation.
    // We map each group to one b_index_x.
    if (group_id >= blk) return;

    int b_index_x = group_id;
    int b_index_y = blk - 1 - b_index_x;

    int global_row_start = b_index_y * BLOCK_SIZE;
    int global_col_start = b_index_x * BLOCK_SIZE;

    // Load reference block (BLOCK_SIZE x BLOCK_SIZE) into local memory
    // Distribute rows among threads
    for (int i = local_id; i < BLOCK_SIZE; i += BLOCK_SIZE) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            int r_idx = max_cols * (global_row_start + i + 1) + global_col_start + j + 1;
            reference_l[i * BLOCK_SIZE + j] = referrence[r_idx];
        }
    }

    // Load input block (BLOCK_SIZE+1 x BLOCK_SIZE+1) into local memory
    // Distribute rows among threads
    for (int i = local_id; i < BLOCK_SIZE + 1; i += BLOCK_SIZE) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            int idx = max_cols * (global_row_start + i) + global_col_start + j;
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[idx];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Compute DP for this block
    // Since dependencies are strict (i-1, j-1), we run the serial loops on thread 0
    // or distribute carefully. Given the small size (16x16), running on thread 0 is efficient enough
    // and matches the original serial logic inside the parallel block loop.
    if (local_id == 0) {
        for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
            for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
                int diag = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1];
                int left = input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty;
                int up = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty;
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(diag, left, up);
            }
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Write results back to global memory
    // Distribute rows among threads
    for (int i = local_id; i < BLOCK_SIZE; i += BLOCK_SIZE) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            int idx = max_cols * (global_row_start + i + 1) + global_col_start + j + 1;
            input_itemsets[idx] = input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

__attribute__((reqd_work_group_size(BLOCK_SIZE, 1, 1)))
void nw_kernel2(__global int* referrence,
                __global int* input_itemsets,
                __global int* output_itemsets,
                __local int* input_itemsets_l,
                __local int* reference_l,
                int max_cols,
                int penalty,
                int blk,
                int block_width,
                int worksize,
                int offset_r,
                int offset_c)
{
    int local_id = get_local_id(0);
    int group_id = get_group_id(0);

    // OpenMP loop: b_index_x from blk-1 to (max_cols-1)/BLOCK_SIZE - 1 (which is block_width - 1)
    int min_x = blk - 1;
    int max_x = block_width - 1;

    if (group_id < min_x || group_id > max_x) return;

    int b_index_x = group_id;
    int b_index_y = block_width + blk - 2 - b_index_x;

    int global_row_start = b_index_y * BLOCK_SIZE;
    int global_col_start = b_index_x * BLOCK_SIZE;

    // Load reference block
    for (int i = local_id; i < BLOCK_SIZE; i += BLOCK_SIZE) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            int r_idx = max_cols * (global_row_start + i + 1) + global_col_start + j + 1;
            reference_l[i * BLOCK_SIZE + j] = referrence[r_idx];
        }
    }

    // Load input block
    for (int i = local_id; i < BLOCK_SIZE + 1; i += BLOCK_SIZE) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            int idx = max_cols * (global_row_start + i) + global_col_start + j;
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[idx];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Compute DP
    if (local_id == 0) {
        for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
            for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
                int diag = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1];
                int left = input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty;
                int up = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty;
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(diag, left, up);
            }
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Write results
    for (int i = local_id; i < BLOCK_SIZE; i += BLOCK_SIZE) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            int idx = max_cols * (global_row_start + i + 1) + global_col_start + j + 1;
            input_itemsets[idx] = input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}
